const { ApolloServer } = require('@apollo/server');
const { expressMiddleware } = require('@apollo/server/express4');
const { ApolloServerPluginDrainHttpServer } = require('@apollo/server/plugin/drainHttpServer');
const { makeExecutableSchema } = require('@graphql-tools/schema');
const { WebSocketServer } = require('ws');
const { useServer } = require('graphql-ws/lib/use/ws');
const express = require('express');
const { createServer } = require('http');
const { PubSub } = require('graphql-subscriptions');
const cors = require('cors');
const bodyParser = require('body-parser');
const { GraphQLError } = require('graphql');
const crypto = require('crypto');

const pubsub = new PubSub();

const chatRooms = new Map();
const messages = new Map();
const users = new Map();

const MAX_MESSAGE_LENGTH = 5000;
const MAX_ROOM_ID_LENGTH = 100;
const MAX_USERNAME_LENGTH = 50;
const MAX_CONTENT_LENGTH = 10000;
const RATE_LIMIT_WINDOW = 60000;
const MAX_REQUESTS_PER_WINDOW = 100;

const requestCounts = new Map();

function validateString(value, maxLength, fieldName) {
  if (typeof value !== 'string') {
    throw new GraphQLError(`${fieldName} must be a string`, {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  
  if (value.length === 0) {
    throw new GraphQLError(`${fieldName} cannot be empty`, {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  
  if (value.length > maxLength) {
    throw new GraphQLError(`${fieldName} exceeds maximum length of ${maxLength}`, {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  
  const sanitized = value.trim();
  if (sanitized.length === 0) {
    throw new GraphQLError(`${fieldName} cannot be empty after trimming`, {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  
  return sanitized;
}

function validateRoomId(roomId) {
  const sanitized = validateString(roomId, MAX_ROOM_ID_LENGTH, 'Room ID');
  
  if (!/^[a-zA-Z0-9_-]+$/.test(sanitized)) {
    throw new GraphQLError('Room ID contains invalid characters. Only alphanumeric, underscore, and hyphen allowed', {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  
  return sanitized;
}

function validateMessageContent(content) {
  return validateString(content, MAX_MESSAGE_LENGTH, 'Message content');
}

function validateUsername(username) {
  const sanitized = validateString(username, MAX_USERNAME_LENGTH, 'Username');
  
  if (!/^[a-zA-Z0-9_-]+$/.test(sanitized)) {
    throw new GraphQLError('Username contains invalid characters. Only alphanumeric, underscore, and hyphen allowed', {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  
  return sanitized;
}

function checkRateLimit(identifier) {
  const now = Date.now();
  const userRequests = requestCounts.get(identifier) || [];
  
  const recentRequests = userRequests.filter(timestamp => now - timestamp < RATE_LIMIT_WINDOW);
  
  if (recentRequests.length >= MAX_REQUESTS_PER_WINDOW) {
    throw new GraphQLError('Rate limit exceeded. Please try again later.', {
      extensions: { code: 'RATE_LIMIT_EXCEEDED' }
    });
  }
  
  recentRequests.push(now);
  requestCounts.set(identifier, recentRequests);
}

function authenticateUser(token) {
  if (!token) {
    throw new GraphQLError('Authentication required', {
      extensions: { code: 'UNAUTHENTICATED' }
    });
  }
  
  const user = users.get(token);
  if (!user) {
    throw new GraphQLError('Invalid authentication token', {
      extensions: { code: 'UNAUTHENTICATED' }
    });
  }
  
  return user;
}

const typeDefs = `
  type Message {
    id: ID!
    roomId: String!
    content: String!
    username: String!
    timestamp: String!
  }
  
  type ChatRoom {
    id: ID!
    name: String!
    messageCount: Int!
  }
  
  type AuthPayload {
    token: String!
    username: String!
  }
  
  type Query {
    messages(roomId: String!, limit: Int): [Message!]!
    chatRooms: [ChatRoom!]!
  }
  
  type Mutation {
    authenticate(username: String!): AuthPayload!
    sendMessage(roomId: String!, content: String!): Message!
    createRoom(roomId: String!, name: String!): ChatRoom!
  }
  
  type Subscription {
    messageAdded(roomId: String!): Message!
  }
`;

const resolvers = {
  Query: {
    messages: (_, { roomId, limit = 50 }, context) => {
      authenticateUser(context.token);
      
      const validatedRoomId = validateRoomId(roomId);
      
      if (typeof limit !== 'number' || limit < 1 || limit > 100) {
        throw new GraphQLError('Limit must be between 1 and 100', {
          extensions: { code: 'BAD_USER_INPUT' }
        });
      }
      
      const roomMessages = messages.get(validatedRoomId) || [];
      return roomMessages.slice(-limit);
    },
    
    chatRooms: (_, __, context) => {
      authenticateUser(context.token);
      
      return Array.from(chatRooms.values());
    }
  },
  
  Mutation: {
    authenticate: (_, { username }) => {
      const validatedUsername = validateUsername(username);
      
      const token = crypto.randomBytes(32).toString('hex');
      
      users.set(token, {
        username: validatedUsername,
        createdAt: new Date().toISOString()
      });
      
      return {
        token,
        username: validatedUsername
      };
    },
    
    sendMessage: (_, { roomId, content }, context) => {
      const user = authenticateUser(context.token);
      checkRateLimit(context.token);
      
      const validatedRoomId = validateRoomId(roomId);
      const validatedContent = validateMessageContent(content);
      
      if (!chatRooms.has(validatedRoomId)) {
        throw new GraphQLError('Chat room does not exist', {
          extensions: { code: 'BAD_USER_INPUT' }
        });
      }
      
      const message = {
        id: crypto.randomBytes(16).toString('hex'),
        roomId: validatedRoomId,
        content: validatedContent,
        username: user.username,
        timestamp: new Date().toISOString()
      };
      
      if (!messages.has(validatedRoomId)) {
        messages.set(validatedRoomId, []);
      }
      
      const roomMessages = messages.get(validatedRoomId);
      roomMessages.push(message);
      
      if (roomMessages.length > 1000) {
        messages.set(validatedRoomId, roomMessages.slice(-1000));
      }
      
      pubsub.publish(`MESSAGE_ADDED_${validatedRoomId}`, {
        messageAdded: message
      });
      
      return message;
    },
    
    createRoom: (_, { roomId, name }, context) => {
      authenticateUser(context.token);
      checkRateLimit(context.token);
      
      const validatedRoomId = validateRoomId(roomId);
      const validatedName = validateString(name, MAX_ROOM_ID_LENGTH, 'Room name');
      
      if (chatRooms.has(validatedRoomId)) {
        throw new GraphQLError('Chat room already exists', {
          extensions: { code: 'BAD_USER_INPUT' }
        });
      }
      
      const room = {
        id: validatedRoomId,
        name: validatedName,
        messageCount: 0
      };
      
      chatRooms.set(validatedRoomId, room);
      messages.set(validatedRoomId, []);
      
      return room;
    }
  },
  
  Subscription: {
    messageAdded: {
      subscribe: (_, { roomId }, context) => {
        authenticateUser(context.token);
        
        const validatedRoomId = validateRoomId(roomId);
        
        if (!chatRooms.has(validatedRoomId)) {
          throw new GraphQLError('Chat room does not exist', {
            extensions: { code: 'BAD_USER_INPUT' }
          });
        }
        
        return pubsub.asyncIterator([`MESSAGE_ADDED_${validatedRoomId}`]);
      }
    }
  }
};

async function startServer() {
  const app = express();
  const httpServer = createServer(app);
  
  const schema = makeExecutableSchema({ typeDefs, resolvers });
  
  const wsServer = new WebSocketServer({
    server: httpServer,
    path: '/graphql',
  });
  
  const serverCleanup = useServer({
    schema,
    context: async (ctx) => {
      const token = ctx.connectionParams?.token || ctx.connectionParams?.authorization?.replace('Bearer ', '');
      return { token };
    },
    onConnect: async (ctx) => {
      const token = ctx.connectionParams?.token || ctx.connectionParams?.authorization?.replace('Bearer ', '');
      
      if (!token) {
        throw new Error('Authentication required for WebSocket connection');
      }
      
      if (!users.has(token)) {
        throw new Error('Invalid authentication token');
      }
      
      return true;
    }
  }, wsServer);
  
  const server = new ApolloServer({
    schema,
    plugins: [
      ApolloServerPluginDrainHttpServer({ httpServer }),
      {
        async serverWillStart() {
          return {
            async drainServer() {
              await serverCleanup.dispose();
            }
          };
        }
      }
    ],
    introspection: process.env.NODE_ENV !== 'production',
    validationRules: [],
  });
  
  await server.start();
  
  app.use(
    '/graphql',
    cors({
      origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
      credentials: true
    }),
    bodyParser.json({ limit: '1mb' }),
    expressMiddleware(server, {
      context: async ({ req }) => {
        const token = req.headers.authorization?.replace('Bearer ', '') || '';
        return { token };
      }
    })
  );
  
  const PORT = process.env.PORT || 4000;
  
  httpServer.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}/graphql`);
    console.log(`WebSocket endpoint: ws://localhost:${PORT}/graphql`);
  });
}

startServer().catch(console.error);